module.exports = function(RED) {
    function TextInjectNode(config) {
        RED.nodes.createNode(this, config);
        const node = this;
        node.text = config.text;
        node.on("input", function(msg) {
            msg.payload = node.text || "";
            node.send(msg);
        });
    }
    RED.nodes.registerType("Text Input", TextInjectNode);
}